268: // handleRootHealth returns an http.HandlerFunc that serves the provided checks.
269: func handleRootHealth(name string, firstTimeHealthy func(), checks ...HealthChecker) http.HandlerFunc {
270: 	var notifyOnce sync.Once
271: 	return func(w http.ResponseWriter, r *http.Request) {
272: 		excluded := getExcludedChecks(r)
273: 		unknownExcluded := excluded.Clone()
274: 		// failedVerboseLogOutput is for output to the log.  It indicates detailed failed output information for the log.
275: 		var failedVerboseLogOutput bytes.Buffer
276: 		var failedChecks []string
277: 		var individualCheckOutput bytes.Buffer
278: 		for _, check := range checks {
279: 			// no-op the check if we've specified we want to exclude the check
280: 			if excluded.Has(check.Name()) {
281: 				unknownExcluded.Delete(check.Name())
282: 				fmt.Fprintf(&individualCheckOutput, "[+]%s excluded: ok\n", check.Name())
283: 				continue
284: 			}
285: 			// no-op the check if it is a grouped check and we want to exclude the group
286: 			if check, ok := check.(GroupedHealthChecker); ok && excluded.Has(check.GroupName()) {
287: 				unknownExcluded.Delete(check.GroupName())
288: 				fmt.Fprintf(&individualCheckOutput, "[+]%s excluded with %s: ok\n", check.Name(), check.GroupName())
289: 				continue
290: 			}
291: 			if err := check.Check(r); err != nil {
292: 				slis.ObserveHealthcheck(context.Background(), check.Name(), name, slis.Error)
293: 				// don't include the error since this endpoint is public.  If someone wants more detail
294: 				// they should have explicit permission to the detailed checks.
295: 				fmt.Fprintf(&individualCheckOutput, "[-]%s failed: reason withheld\n", check.Name())
296: 				// but we do want detailed information for our log
297: 				fmt.Fprintf(&failedVerboseLogOutput, "[-]%s failed: %v\n", check.Name(), err)
298: 				failedChecks = append(failedChecks, check.Name())
299: 			} else {
300: 				slis.ObserveHealthcheck(context.Background(), check.Name(), name, slis.Success)
