795: 		data.Version = hs.Cfg.BuildVersion
796: 		data.Commit = hs.Cfg.BuildCommit
797: 		if hs.Cfg.EnterpriseBuildCommit != "NA" && hs.Cfg.EnterpriseBuildCommit != "" {
798: 			data.EnterpriseCommit = hs.Cfg.EnterpriseBuildCommit
799: 		}
800: 	}
801: 
802: 	if !hs.databaseHealthy(ctx.Req.Context()) {
803: 		data.Database = "failing"
804: 		ctx.Resp.Header().Set("Content-Type", "application/json; charset=UTF-8")
805: 		ctx.Resp.WriteHeader(http.StatusServiceUnavailable)
806: 	} else {
807: 		ctx.Resp.Header().Set("Content-Type", "application/json; charset=UTF-8")
808: 		ctx.Resp.WriteHeader(http.StatusOK)
809: 	}
